import{_ as e}from"./chunks/placeholder.DuiHaLuQ.js";import{_ as i,o as s,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"集成方式","description":"","frontmatter":{"title":"集成方式"},"headers":[],"relativePath":"hardware/legacy-evb/integration.md","filePath":"hardware/legacy-evb/integration.md","lastUpdated":null}'),l={name:"hardware/legacy-evb/integration.md"};function n(h,a,p,o,d,c){return s(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="接入方式" tabindex="-1">接入方式 <a class="header-anchor" href="#接入方式" aria-label="Permalink to &quot;接入方式&quot;">​</a></h1><p>AIUI 评估板提供了多种集成方式。在后期量产时，请<a href="/faq/contact.html">联系我们</a>获取更完整的集成流程。</p><h2 id="核心板模式" tabindex="-1">核心板模式 <a class="header-anchor" href="#核心板模式" aria-label="Permalink to &quot;核心板模式&quot;">​</a></h2><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><p>适用于故事机、智能音箱等一些无屏交互的场景。</p><h3 id="集成说明" tabindex="-1">集成说明 <a class="header-anchor" href="#集成说明" aria-label="Permalink to &quot;集成说明&quot;">​</a></h3><p>开发者APP集成<a href="/hardware/legacy-evb/aiui-service-kit.html">AIUIServiceKit</a>，运行在AIUI模块上，从AIUIService获取结果，进行解析处理，与评估板上AIUIProductDemo的效果类似，完整结构如下图所示：</p><p><img src="'+e+`" alt="待补充：AIUI 评估板集成架构图01"></p><p>具体集成方法请参见<a href="/hardware/legacy-evb/aiui-service-kit.html">AIUIServiceKit SDK</a>，对AIUI核心板模块有任何疑问的可参考<a href="https://xfyun-doc.cn-bj.ufileos.com/1519542857029703/AIUI%E6%A8%A1%E5%9D%97XFAI0801%E6%95%B0%E6%8D%AE%E6%89%8B%E5%86%8CV0.3.pdf" target="_blank" rel="noreferrer"><code>AIUI模块数据手册</code></a>。</p><h3 id="开发者程序自启动" tabindex="-1">开发者程序自启动 <a class="header-anchor" href="#开发者程序自启动" aria-label="Permalink to &quot;开发者程序自启动&quot;">​</a></h3><p>Android 4.4之后的版本，默认新安装未启动的程序处于Stopped状态，无法接受系统广播BOOT_COMPLETE实现自启动，所以AIUI添加对第三方应用自启动的支持。</p><p>第三方应用只需要创建Receiver，按照如下的配置接收AIUI的广播即可:</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">receiver</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> android:name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.BootReceiver&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">intent-filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">action</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> android:name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.iflytek.aiuilauncher.action.BOOT_START&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">intent-filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">receiver</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="软核模式" tabindex="-1">软核模式 <a class="header-anchor" href="#软核模式" aria-label="Permalink to &quot;软核模式&quot;">​</a></h2><p>软核模式和<a href="/hardware/legacy-evb/integration.html">核心板模式</a>的软件结构是一样的，区别在于软核模式将AIUIService及其他Apk运行在开发者的硬件上（操作系统需要是Android）。</p><p>集成的时候AIUI只提供AIUI软件APK，所以称为软核模式。</p><h3 id="适用场景-1" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-1" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><p>适用于硬件上需要灵活定制的场景。</p><h3 id="集成说明-1" tabindex="-1">集成说明 <a class="header-anchor" href="#集成说明-1" aria-label="Permalink to &quot;集成说明&quot;">​</a></h3><p>AIUI软核方案对开发者的硬件设计和录音都有一定的要求：</p><ul><li><p>加密芯片</p><p>AIUI只有在有加密芯片的硬件上才能正常运行，所以开发者的定制硬件上需要有加密芯片。</p></li><li><p>录音</p><p>AIUI录音没有使用默认的录音机，而是系统定制中的Alsa(Advanced Linux Sound Architecture)录音机， 开发者集成软核方案时可以选择自己录音通过AIUI ServiceKit SDK写入原始音频，也可以修改系统支持Alsa。</p></li></ul><p>具体的要求和对接开发事项请<a href="/faq/contact.html">联系我们</a>。</p><h3 id="麦克风阵列方案迁移" tabindex="-1">麦克风阵列方案迁移 <a class="header-anchor" href="#麦克风阵列方案迁移" aria-label="Permalink to &quot;麦克风阵列方案迁移&quot;">​</a></h3><p>如果采用了麦克风阵列的软核方案，那迁移到AIUI软核方案就十分简单，因为上面提到的加密芯片和录音的要求均已达到。</p><p>按以下步骤集成：</p><p>① 在开发集成评估时，将加密芯片替换为AIUI测试加密芯片，在测试完成量产时，再使用厂商特定AIUI加密芯片。</p><blockquote><p>不同加密芯片需要联系商务提供特定版本的AIUIService apk。联系时请说明以下参数：</p><ul><li>几麦</li><li>加密密钥挂载位置</li><li>通道号是默认还是有其他需求</li></ul></blockquote><p>② 修改AIUI配置文件中的<code>alsa</code>参数下的<code>sound_card</code>和<code>sample_rate</code>参数为麦克风软核阵列方案确定的录音参数。</p><p>③ 开发集成参考<a href="/hardware/legacy-evb/integration.html">核心板模式</a>。</p><h2 id="上位机模式" tabindex="-1">上位机模式 <a class="header-anchor" href="#上位机模式" aria-label="Permalink to &quot;上位机模式&quot;">​</a></h2><h3 id="适用场景-2" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-2" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><p>适用：上位机和AIUI模块通过串口通信，适用于有屏幕需求或硬件扩展需求（如机器人，智能家居等）。</p><h3 id="集成说明-2" tabindex="-1">集成说明 <a class="header-anchor" href="#集成说明-2" aria-label="Permalink to &quot;集成说明&quot;">​</a></h3><p><img src="`+e+'" alt="待补充：AIUI 评估板集成架构图02"></p><p>如上图所示，为上位机模式的开发结构图，UARTService充当AIUIService和上位机之间的中介，一面负责将AIUI的结果通过串口发送给上位机，一面将上位机通过串口发送的指令发送到AIUI。</p><p>AIUIProductDemo是个可选的选项，因为如果在上位机上对结果进行解析播放，那么AIUI模块上的AIUIProductDemo的播报就不必要了。</p><p>具体集成方法请参见<a href="/hardware/legacy-evb/serial-sdk.html">串口SDK</a>。</p>',37)])])}const E=i(l,[["render",n]]);export{u as __pageData,E as default};
